// src/components/LiveStreamPlayer.jsx
import React, { useEffect, useRef, useState } from "react";
import videojs from "video.js";
import "video.js/dist/video-js.css";

const STREAM_URL = "https://live.bodephatquoc.org/bdpq/kenh1/playlist.m3u8";
const TONG_CHI_IMAGE = "https://ik.imagekit.io/dloitl7fd8/enhan.png";
const LAYER_IMAGE = "https://ik.imagekit.io/dloitl7fd8/image%2015.png?updatedAt=1767830765297";

export const LiveStreamPlayer = ({ poster, src = STREAM_URL }: any) => {
  const videoRef: any = useRef(null);
  const playerRef: any = useRef(null);
  const [isStarted, setIsStarted] = useState(false);

  useEffect(() => {
    if (!playerRef.current && videoRef.current) {
      playerRef.current = videojs(videoRef.current, {
        autoplay: false,
        controls: true,
        fluid: true,
        liveui: true,
        poster: poster || TONG_CHI_IMAGE,
        sources: [{ src: src, type: "application/x-mpegURL" }],
      });

      // EXACT SAME POSTER LOGIC YOU PROVIDED
      playerRef.current.on('ready', () => {
        const posterEl = playerRef.current.posterCanvas_ || playerRef.current.getChild('poster')?.el();
        if (posterEl) {
          posterEl.style.backgroundSize = 'cover';
          posterEl.style.backgroundPosition = 'center';
          posterEl.style.width = '100%';
          posterEl.style.height = '100%';
        }
      });

      // Hide overlay when play starts
      playerRef.current.on('play', () => setIsStarted(true));
    }

    if (playerRef.current && poster) {
      playerRef.current.poster(poster);
    }

    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, [poster, src]);

  const handleOverlayClick = () => {
    if (playerRef.current) {
      playerRef.current.play();
    }
  };

  return (
    <div 
      data-vjs-player 
      style={{ 
        width: '100%', 
        position: 'relative', 
        overflow: 'hidden',
        backgroundColor: '#000' 
      }}
    >
      {/* ADDING ONLY THIS OVERLAY LAYER ON TOP */}
      {!isStarted && (
        <div 
          onClick={handleOverlayClick}
          style={{
            position: 'absolute',
            bottom: '20px', 
            left: '20px',
            width: '25%',
            height: '25%',
            zIndex: 10,
            cursor: 'pointer',
            backgroundImage: `url("${LAYER_IMAGE}")`,
            backgroundSize: 'contain',
            backgroundPosition: 'left bottom',
            backgroundRepeat: 'no-repeat',
          }}
        />
      )}

      <video
        ref={videoRef}
        className="video-js vjs-big-play-centered"
        style={{ width: '100%', height: '100%' }}
      />
    </div>
  );
};

export const LiveStreamPlayerExample = () => {
  return <LiveStreamPlayer poster={TONG_CHI_IMAGE} />;
};

export default LiveStreamPlayer;